export const SQL_FILES: Record<string, string> = {
  "q01_state_overview.sql": "-- =============================================================================\n-- q01_state_overview.sql — Mississippi-wide context for the EGI analysis\n-- =============================================================================\n-- PURPOSE:    Establish the state-level baseline the README opens on. Three\n--             sections: (1) which 5 datasets feed the analysis,\n--             (2) geographic + demographic + provider scope (one row),\n--             (3) all 10 burden-composite measures, ranked by state-mean\n--             age-adjusted prevalence.\n-- TABLES:     data_sources, counties, provider_capacity, taxonomies,\n--             health_indicators, measures\n-- TECHNIQUES: CTEs, multi-CTE composition, multi-table JOINs, aggregate\n--             functions (AVG/SUM/MIN/MAX/COUNT), ORDER BY, LIMIT\n-- OUTPUT:     Three result sets. The CSV exporter saves the third (top\n--             burden measures) as data/processed/q01_state_overview.csv\n--             — that table is what the README opens with.\n-- DESIGN:     The simplest query in the suite. Establishes the header\n--             comment format, the year-mix CTE pattern (see Section 3\n--             note), the age-adjusted filter convention, and the\n--             multi-section \"context\" structure that none of the deeper\n--             queries (q02-q08) use. Section 1's output (5 rows) is the\n--             audit-trail proof: every fact reported in q02-q08 traces\n--             to one of these 5 federal sources.\n-- =============================================================================\n\n-- ----------------------------------------------------------------------------\n-- SECTION 1 — Data provenance (5 rows; one per loaded dataset)\n-- ----------------------------------------------------------------------------\nSELECT\n    source_id,\n    publisher,\n    vintage,\n    retrieval_date,\n    rows_loaded,\n    notes\nFROM data_sources\nORDER BY publisher, source_id;\n\n\n-- ----------------------------------------------------------------------------\n-- SECTION 2 — Geographic + demographic + provider scope (one row)\n--\n-- Note: total_primary_care_providers = 6,377 county-attributable providers.\n-- 27 NPPES providers across 14 unmatched ZIPs (D-010 PO-box, 1 AL border,\n-- 1 likely FL typo) are excluded; 27 are preserved in the providers\n-- table with fips=NULL for audit.\n-- ----------------------------------------------------------------------------\nWITH\ngeo AS (\n    SELECT COUNT(*) AS n_counties, SUM(population) AS total_population\n    FROM counties\n),\ncapacity AS (\n    SELECT SUM(provider_count) AS total_primary_care_providers\n    FROM provider_capacity\n)\nSELECT\n    g.n_counties,\n    g.total_population,\n    c.total_primary_care_providers,\n    ROUND(1.0 * c.total_primary_care_providers * 10000.0 / g.total_population, 2)\n        AS state_pcp_per_10k\nFROM geo g, capacity c;\n\n\n-- ----------------------------------------------------------------------------\n-- SECTION 3 — All 10 burden-composite measures, ranked by state-mean age-adjusted prevalence\n-- ----------------------------------------------------------------------------\n-- Year-mix handling note (recurs in q02, q05, q06, q08):\n--   PLACES 2025 release contains both 2022 and 2023 BRFSS rows. 4 measures\n--   (BPHIGH, BPMED, CHOLSCREEN, HIGHCHOL) still use 2022 BRFSS pending\n--   updated estimates; the other 36 moved to 2023. To compare counties\n--   fairly we always pick MAX(year) per measure_id via the `latest` CTE\n--   below.\n-- ----------------------------------------------------------------------------\n\nWITH latest AS (\n    SELECT measure_id, MAX(year) AS y\n    FROM health_indicators\n    GROUP BY measure_id\n)\nSELECT\n    m.measure_id,\n    m.measure_short,\n    m.category,\n    l.y AS year,\n    ROUND(AVG(hi.data_value), 2) AS state_mean_age_adj_pct,\n    ROUND(MIN(hi.data_value), 2) AS county_min_pct,\n    ROUND(MAX(hi.data_value), 2) AS county_max_pct\nFROM measures m\nJOIN latest l            ON l.measure_id  = m.measure_id\nJOIN health_indicators hi ON hi.measure_id = m.measure_id\n                         AND hi.year       = l.y\n                         AND hi.data_value_type = 'Age-adjusted prevalence'\nWHERE m.is_in_burden_composite = 1\nGROUP BY m.measure_id, m.measure_short, m.category, l.y\nORDER BY state_mean_age_adj_pct DESC;\n",
  "q02_burden_ranking.sql": "-- =============================================================================\n-- q02_burden_ranking.sql — counties ranked by composite health burden\n-- =============================================================================\n-- PURPOSE:    Rank Mississippi's 82 counties by a composite burden score\n--             that combines the 10 PLACES burden-composite measures (D-011).\n--             Higher burden_score = more disease + worse healthcare access.\n-- TABLES:     health_indicators, measures, counties\n-- TECHNIQUES: 4 CTEs (latest year, polarity-flipped raw, per-measure min-max\n--             normalization via window, per-county aggregation),\n--             DENSE_RANK() OVER (ORDER BY ...), NTILE(5) OVER (...) for\n--             quintiles, window function MIN/MAX with PARTITION BY,\n--             multi-table JOINs.\n-- OUTPUT:     82 rows: fips, county_name, region, population, burden_score\n--             [0-100], measures_included [should be 10 for every row],\n--             burden_rank [1-82, 1=worst], burden_quintile [1-5, 1=worst].\n-- DESIGN:     Polarity (D-011) is multiplied BEFORE per-measure normalization\n--             so that the 2 inverted burden measures (CHECKUP, CHOLSCREEN)\n--             contribute to burden in the SAME direction as the other 8\n--             after normalization. Per-measure normalization (vs pooled)\n--             equalizes the influence of measures with very different scales\n--             (OBESITY 36-53% vs CHD 5-8%). Year-mix handled via the latest\n--             CTE pattern established in q01 (see q01 header for the note).\n--             DENSE_RANK is used (not RANK) so that \"burden_rank <= 10\"\n--             yields at most 10 distinct score levels — cleaner \"top 10\"\n--             framing in the README and presentation.\n-- =============================================================================\n\nWITH\n-- 1. Latest PLACES year per measure (4 measures still on 2022 BRFSS,\n--    the other 6 of the burden composite use 2023 — pick latest per measure).\nlatest AS (\n    SELECT measure_id, MAX(year) AS y\n    FROM health_indicators\n    GROUP BY measure_id\n),\n\n-- 2. Burden composite rows only, age-adjusted, polarity applied.\n--    polarized_value: same magnitude as the raw % but sign-flipped for the\n--    2 measures whose polarity = -1 (CHECKUP, CHOLSCREEN). After flipping,\n--    \"higher value = more burdened\" for every measure.\nburden_raw AS (\n    SELECT\n        hi.fips,\n        hi.measure_id,\n        m.polarity * hi.data_value AS polarized_value\n    FROM health_indicators hi\n    JOIN measures m USING (measure_id)\n    JOIN latest l   ON l.measure_id = hi.measure_id AND l.y = hi.year\n    WHERE m.is_in_burden_composite = 1\n      AND hi.data_value_type       = 'Age-adjusted prevalence'\n      AND hi.data_value IS NOT NULL\n),\n\n-- 3. Min-max normalize each measure across the 82 counties to a 0-100\n--    \"burden contribution\" scale (PARTITION BY measure_id so each measure\n--    is normalized against its own range). NULLIF guards against a\n--    zero-range measure (which shouldn't happen in practice).\nburden_normalized AS (\n    SELECT\n        fips,\n        measure_id,\n        100.0 * (polarized_value - MIN(polarized_value) OVER (PARTITION BY measure_id))\n              / NULLIF(  MAX(polarized_value) OVER (PARTITION BY measure_id)\n                       - MIN(polarized_value) OVER (PARTITION BY measure_id),\n                       0)\n            AS normalized_score\n    FROM burden_raw\n),\n\n-- 4. Mean of the 10 normalized scores per county = composite burden score.\n--    measures_included is surfaced for defensibility: any county with\n--    fewer than 10 contributing measures (e.g., if PLACES suppressed a\n--    value) becomes visible in the output rather than silently averaged\n--    over a smaller set.\nburden_composite AS (\n    SELECT\n        fips,\n        ROUND(AVG(normalized_score), 2) AS burden_score,\n        COUNT(*) AS measures_included     -- always 10 in current data; surface for defensibility\n    FROM burden_normalized\n    WHERE normalized_score IS NOT NULL    -- exclude any NULL normalized scores from the count too\n    GROUP BY fips\n)\n\n-- 5. Join county metadata, rank (DENSE_RANK so \"top 10\" is at most 10\n--    distinct levels), quintile (1 = most burdened).\nSELECT\n    c.fips,\n    c.county_name,\n    c.region,\n    c.population,\n    bc.burden_score,\n    bc.measures_included,\n    DENSE_RANK() OVER (ORDER BY bc.burden_score DESC) AS burden_rank,\n    NTILE(5)     OVER (ORDER BY bc.burden_score DESC) AS burden_quintile\nFROM burden_composite bc\nJOIN counties c USING (fips)\nORDER BY burden_rank;\n",
  "q03_capacity_ranking.sql": "-- =============================================================================\n-- q03_capacity_ranking.sql — counties ranked by primary-care capacity scarcity\n-- =============================================================================\n-- PURPOSE:    Rank Mississippi's 82 counties by primary-care provider\n--             SCARCITY. Higher capacity_gap_score = fewer providers per\n--             capita = more underserved.\n-- TABLES:     provider_capacity, counties\n-- TECHNIQUES: 3 CTEs (per-county provider sum, density metric, min-max\n--             scoring via window function), DENSE_RANK() OVER (ORDER BY ...),\n--             NTILE(5) OVER (...) for quintiles, MIN/MAX OVER () for\n--             state-wide normalization.\n-- OUTPUT:     82 rows: fips, county_name, region, population,\n--             total_providers, pcp_per_10k, capacity_gap_score [0-100],\n--             capacity_rank [1-82, 1=worst], capacity_quintile [1-5, 1=worst].\n-- DESIGN:     pcp_per_10k = primary-care providers per 10,000 residents\n--             (D-008 taxonomies, county-attributed via D-010 crosswalk).\n--             capacity_gap_score INVERTS the normalized density so that a\n--             county with the lowest pcp_per_10k gets the highest gap\n--             score (100 = worst capacity, 0 = best). Quintile=1 is the\n--             most underserved quintile by capacity. DENSE_RANK (not RANK)\n--             is used so \"top 10 underserved\" returns at most 10 distinct\n--             gap-score levels.\n-- =============================================================================\n\nWITH\n-- 1. Total active primary-care providers per county (sum across 6 taxonomies).\n--    Includes zero-count rows for taxonomies that don't appear in a county\n--    (loader seeded those for join safety).\npc_total AS (\n    -- total_providers excludes the 27 NPPES providers across 14 unmatched\n    -- ZIPs (D-010 PO-box + 1 AL border + 1 likely FL typo). Those providers\n    -- are preserved in the providers table with fips IS NULL for audit.\n    SELECT fips, SUM(provider_count) AS total_providers\n    FROM provider_capacity\n    GROUP BY fips\n),\n\n-- 2. Density metric: providers per 10,000 residents.\n--    Cast to REAL via 1.0 * ... to avoid SQLite integer division.\ncapacity_raw AS (\n    SELECT\n        c.fips,\n        pct.total_providers,\n        1.0 * pct.total_providers * 10000.0 / c.population AS pcp_per_10k\n    FROM counties c\n    JOIN pc_total pct USING (fips)\n),\n\n-- 3. Min-max normalize pcp_per_10k to 0-100, then INVERT so that\n--    capacity_gap_score is high when capacity is low.\n--    gap = 100 - normalized(pcp_per_10k).\ncapacity_scored AS (\n    SELECT\n        fips,\n        total_providers,\n        pcp_per_10k,\n        100.0 - 100.0 * (pcp_per_10k - MIN(pcp_per_10k) OVER ())\n                      / NULLIF(  MAX(pcp_per_10k) OVER ()\n                               - MIN(pcp_per_10k) OVER (),\n                               0)\n            AS capacity_gap_score\n    FROM capacity_raw\n)\n\n-- 4. Join county metadata, rank (DENSE_RANK so \"top 10 underserved\" is at\n--    most 10 distinct levels), quintile.\nSELECT\n    c.fips,\n    c.county_name,\n    c.region,\n    c.population,\n    cs.total_providers,\n    ROUND(cs.pcp_per_10k,         2) AS pcp_per_10k,\n    ROUND(cs.capacity_gap_score,  2) AS capacity_gap_score,\n    DENSE_RANK() OVER (ORDER BY cs.capacity_gap_score DESC) AS capacity_rank,\n    NTILE(5)     OVER (ORDER BY cs.capacity_gap_score DESC) AS capacity_quintile\nFROM capacity_scored cs\nJOIN counties c USING (fips)\nORDER BY capacity_rank;\n",
  "q04_vulnerability_layer.sql": "-- =============================================================================\n-- q04_vulnerability_layer.sql — SVI + health context per county\n-- =============================================================================\n-- PURPOSE:    For each of the 82 counties, surface the overall SVI percentile,\n--             the vulnerability quintile, which of the 4 SVI themes is\n--             dominant for that county, and a parallel health-context number\n--             (polarity-aware mean burden indicator). One row per county lets\n--             downstream queries and visuals categorize counties by\n--             vulnerability AND see the health picture together.\n-- TABLES:     counties, social_vulnerability, health_indicators, measures\n-- TECHNIQUES: 2 CTEs (latest year per PLACES measure; per-county polarity-\n--             aware burden context aggregation), multi-table JOIN (4 tables),\n--             CASE statement for dominant_theme label, NTILE(5) window\n--             function for svi_quintile, SQLite scalar max() for\n--             dominant_theme_value, ROUND on REAL outputs.\n-- OUTPUT:     82 rows: fips, county_name, region, population, rpl_themes,\n--             svi_quintile [1-5, 1=most vulnerable], dominant_theme [TEXT],\n--             dominant_theme_value [0-1 percentile], burden_context_signed.\n-- DESIGN:     - burden_context_signed = AVG(polarity * age-adjusted %) across\n--               the 10 burden measures. Polarity-aware so that \"higher = more\n--               burdened\" is consistent across all 10. Note: because the two\n--               negative-polarity measures (CHECKUP, CHOLSCREEN) have larger\n--               absolute values than the disease prevalences they're paired\n--               with, the resulting state-mean is negative; that's expected\n--               — the column is for *relative ordering* across counties, not\n--               for absolute interpretation. The analytical burden composite\n--               lives in q02's burden_score and q05's EGI burden component\n--               (both 0-100 normalized).\n--             - dominant_theme: declared CASE order resolves ties as\n--               theme1 > theme2 > theme3 > theme4. Perfect ties to 4\n--               decimals are extremely rare in practice.\n--             - dominant_theme_value uses SQLite's SCALAR max(a, b, c, d)\n--               which returns NULL if any argument is NULL — defensive for\n--               the (theoretical) all-NULL case. All 82 MS rows have\n--               non-NULL theme values in the current data (DQ check\n--               `range.svi.rpl_themes_populated` confirms).\n--             - Year-mix handled via the `latest` CTE established in q01.\n--             - Convention C2 (age-adjusted only) is applied in the join\n--               filter inside `burden_by_county`.\n-- =============================================================================\n\nWITH\n-- 1. Latest PLACES year per measure (year-mix per Convention C3).\nlatest AS (\n    SELECT measure_id, MAX(year) AS y\n    FROM health_indicators\n    GROUP BY measure_id\n),\n\n-- 2. Per-county polarity-aware AVG across the 10 burden measures, age-adjusted.\n--    Same operation q02 applies for the analytical composite — keeps the\n--    project telling a consistent directional story.\nburden_by_county AS (\n    SELECT\n        hi.fips,\n        AVG(m.polarity * hi.data_value) AS burden_context_signed\n    FROM health_indicators hi\n    JOIN measures m USING (measure_id)\n    JOIN latest l   ON l.measure_id = hi.measure_id AND l.y = hi.year\n    WHERE m.is_in_burden_composite = 1\n      AND hi.data_value_type       = 'Age-adjusted prevalence'\n      AND hi.data_value IS NOT NULL\n    GROUP BY hi.fips\n)\n\n-- 3. Per-county SVI + theme dominance + health context. NTILE(5) over\n--    rpl_themes DESC so quintile=1 holds the 20% most-vulnerable counties.\nSELECT\n    c.fips,\n    c.county_name,\n    c.region,\n    c.population,\n    ROUND(sv.rpl_themes, 4) AS rpl_themes,\n    NTILE(5) OVER (ORDER BY sv.rpl_themes DESC) AS svi_quintile,\n    CASE\n        WHEN sv.rpl_theme1_socioeconomic >= sv.rpl_theme2_household\n         AND sv.rpl_theme1_socioeconomic >= sv.rpl_theme3_minority\n         AND sv.rpl_theme1_socioeconomic >= sv.rpl_theme4_housing_transport\n            THEN 'Socioeconomic Status'\n        WHEN sv.rpl_theme2_household >= sv.rpl_theme3_minority\n         AND sv.rpl_theme2_household >= sv.rpl_theme4_housing_transport\n            THEN 'Household Characteristics'\n        WHEN sv.rpl_theme3_minority >= sv.rpl_theme4_housing_transport\n            THEN 'Racial & Ethnic Minority Status'\n        ELSE 'Housing Type & Transportation'\n    END AS dominant_theme,\n    ROUND(\n        max(sv.rpl_theme1_socioeconomic,\n            sv.rpl_theme2_household,\n            sv.rpl_theme3_minority,\n            sv.rpl_theme4_housing_transport),\n        4\n    ) AS dominant_theme_value,\n    ROUND(b.burden_context_signed, 2) AS burden_context_signed\nFROM counties c\nJOIN social_vulnerability sv USING (fips)\nJOIN burden_by_county b      USING (fips)\nORDER BY sv.rpl_themes DESC;\n",
  "q05_equity_gap_index.sql": "-- =============================================================================\n-- q05_equity_gap_index.sql — THE HEADLINE — Equity Gap Index per county\n-- =============================================================================\n-- PURPOSE:    Identify Mississippi counties with the largest health equity\n--             gaps. The EGI is a single composite score (0-100) that combines\n--             three normalized components: health burden (PLACES), provider\n--             capacity scarcity (NPPES + ACS), and social vulnerability\n--             (CDC/ATSDR SVI). Higher EGI = more underserved. This file\n--             creates the durable analytical artifact `v_equity_gap_index`\n--             that q06/q07/q08, Phase 3.5 stats, and Phase 4 viz all query.\n--\n-- TABLES:     counties, measures, health_indicators, provider_capacity,\n--             social_vulnerability\n--\n-- TECHNIQUES: 10 chained CTEs (weights, latest year, burden polarity-flip,\n--             per-measure min-max via PARTITION BY window, per-county AVG\n--             for burden composite, capacity total, density, state-wide\n--             min-max inverted for capacity, state-wide min-max for\n--             vulnerability, weighted aggregation), DENSE_RANK() OVER ...\n--             for tie-tolerant ranking, NTILE(5) OVER ... for quintiles,\n--             CREATE VIEW for the persisted artifact, intentional duplication\n--             of q02/q03 burden+capacity logic (β-normalization).\n--\n-- OUTPUT:     10 columns per row, 82 rows:\n--               fips, county_name, region, population,\n--               burden_component, capacity_component, vulnerability_component\n--                 (all 0-100; higher = worse for that pillar),\n--               egi_score (0-100; higher = more underserved),\n--               egi_rank (1 = most underserved, DENSE_RANK so ties share rank),\n--               egi_quintile (1 = most underserved quintile)\n--\n-- DESIGN:\n--   D-016: Equal-thirds weighting (1/3 each). County Health Rankings\n--          precedent + transparency + tunability via the single `weights`\n--          CTE. See DECISIONS.md for the four-option rejection table.\n--   D-017: VIEW (not persisted table). At 82-row scale view recomputation\n--          is sub-millisecond; keeps the math auditable in this file.\n--   D-018: All three component scores exposed in the view output (10 cols).\n--          Required by q08 driver-analysis and by judge by-hand\n--          verifiability (every row: 0.333*B + 0.333*C + 0.333*V ≈ EGI).\n--   D-019: No population floor. Smallest counties remain in the ranking.\n--          Issaquena (pop 1,206) is a federally-designated HPSA; if it\n--          tops the EGI, that's independent validation, not noise.\n--\n--   Tie-breaking: ORDER BY egi_score DESC, vulnerability_component DESC,\n--   population DESC, fips ASC. Vulnerability is the most analytically\n--   meaningful first tiebreaker (human-impact dimension); population is a\n--   policy-salience proxy; FIPS is the deterministic tail (so re-runs\n--   produce bit-identical CSVs).\n--\n--   Inline normalization (β): burden/capacity/vulnerability math here\n--   intentionally duplicates q02/q03/q04 so q05 is the canonical EGI\n--   artifact — readable end-to-end without cross-file dependencies. The\n--   math is trivial; drift risk is negligible.\n--\n-- EXPECTED FINDING (design hypothesis):\n--   The #1 EGI county will be either Humphreys (Delta, RPL_themes = 1.000,\n--   burden_score = 78.92 in q02 — the highest-burden county) or Issaquena\n--   (Delta, RPL_themes ≈ 0.95+, capacity_component = 100.00 because the\n--   only county with zero providers). Both are Delta. The top 10 should\n--   be Delta-dominated (q02 showed 8 of top-10 burdened are Delta) and\n--   should include several rural-Pine-Belt / rural-Other counties as\n--   capacity contributes.\n-- =============================================================================\n\nDROP VIEW IF EXISTS v_equity_gap_index;\n\nCREATE VIEW v_equity_gap_index AS\nWITH\n\n-- 1. Weights (D-016) — equal thirds. Single source of truth for tuning.\nweights AS (\n    SELECT 1.0/3.0 AS w_burden,\n           1.0/3.0 AS w_capacity,\n           1.0/3.0 AS w_vulnerability\n),\n\n-- 2. Latest BRFSS year per PLACES measure (Convention C3 year-mix handling).\nlatest AS (\n    SELECT measure_id, MAX(year) AS y\n    FROM health_indicators\n    GROUP BY measure_id\n),\n\n-- 3. Burden raw: for each (county, burden measure), polarity * value.\n--    After this CTE, \"higher = more burdened\" for every measure (the 2\n--    negative-polarity preventive measures get sign-flipped). Duplicates\n--    q02's burden_raw — intentional per β-normalization (see DESIGN).\nburden_raw AS (\n    SELECT\n        hi.fips,\n        hi.measure_id,\n        m.polarity * hi.data_value AS polarized_value\n    FROM health_indicators hi\n    JOIN measures m USING (measure_id)\n    JOIN latest l   ON l.measure_id = hi.measure_id AND l.y = hi.year\n    WHERE m.is_in_burden_composite = 1\n      AND hi.data_value_type       = 'Age-adjusted prevalence'\n      AND hi.data_value IS NOT NULL\n),\n\n-- 4. Burden normalized: per-measure min-max scaling to 0-100 across the\n--    82 counties. PARTITION BY measure_id so each measure is normalized\n--    within its own range (equalizes influence; OBESITY 36-53% doesn't\n--    swamp CHD 5-8%). NULLIF guards against a zero-range measure.\nburden_normalized AS (\n    SELECT\n        fips,\n        measure_id,\n        100.0 * (polarized_value - MIN(polarized_value) OVER (PARTITION BY measure_id))\n              / NULLIF(  MAX(polarized_value) OVER (PARTITION BY measure_id)\n                       - MIN(polarized_value) OVER (PARTITION BY measure_id),\n                       0)\n            AS normalized_score\n    FROM burden_raw\n),\n\n-- 5. Burden per county: AVG of the 10 normalized scores. Final 0-100\n--    burden_component (higher = more burdened).\nburden_per_county AS (\n    SELECT\n        fips,\n        AVG(normalized_score) AS burden_component\n    FROM burden_normalized\n    WHERE normalized_score IS NOT NULL\n    GROUP BY fips\n),\n\n-- 6. Capacity total: active primary-care providers per county, summed\n--    across the 6 HRSA taxonomies. Excludes the 27 NULL-FIPS providers\n--    by construction (they're not in provider_capacity).\ncapacity_total AS (\n    SELECT fips, SUM(provider_count) AS total_providers\n    FROM provider_capacity\n    GROUP BY fips\n),\n\n-- 7. Capacity raw: pcp_per_10k = providers per 10,000 residents.\ncapacity_raw AS (\n    SELECT\n        c.fips,\n        1.0 * ct.total_providers * 10000.0 / c.population AS pcp_per_10k\n    FROM counties c\n    JOIN capacity_total ct USING (fips)\n),\n\n-- 8. Capacity scored: state-wide min-max normalize pcp_per_10k to 0-100,\n--    then INVERT (100 - normalized) so high = worst capacity. Duplicates\n--    q03's capacity_scored CTE — intentional per β-normalization.\ncapacity_scored AS (\n    SELECT\n        fips,\n        100.0 - 100.0 * (pcp_per_10k - MIN(pcp_per_10k) OVER ())\n                      / NULLIF(  MAX(pcp_per_10k) OVER ()\n                               - MIN(pcp_per_10k) OVER (), 0)\n            AS capacity_component\n    FROM capacity_raw\n),\n\n-- 9. Vulnerability scored: state-wide min-max on rpl_themes (already a\n--    0-1 intra-state percentile per D-007). For MS data (min=0, max=1\n--    exactly) this is equivalent to rpl_themes * 100; doing min-max\n--    anyway keeps the operation parallel and defensive.\nvulnerability_scored AS (\n    SELECT\n        fips,\n        100.0 * (rpl_themes - MIN(rpl_themes) OVER ())\n              / NULLIF(  MAX(rpl_themes) OVER ()\n                       - MIN(rpl_themes) OVER (), 0)\n            AS vulnerability_component\n    FROM social_vulnerability\n),\n\n-- 10. Combined: join the three components by FIPS, cross-join the\n--     weights, compute the weighted-sum EGI score (0-100).\ncombined AS (\n    SELECT\n        b.fips,\n        b.burden_component,\n        cs.capacity_component,\n        vs.vulnerability_component,\n          w.w_burden        * b.burden_component\n        + w.w_capacity      * cs.capacity_component\n        + w.w_vulnerability * vs.vulnerability_component AS egi_score\n    FROM burden_per_county    b\n    JOIN capacity_scored      cs USING (fips)\n    JOIN vulnerability_scored vs USING (fips)\n    CROSS JOIN weights        w\n)\n\n-- Final: county metadata + components + EGI + rank + quintile.\n-- Tie-break order per D4: vulnerability first (human impact),\n-- then population (policy salience), then fips (deterministic tail).\nSELECT\n    c.fips,\n    c.county_name,\n    c.region,\n    c.population,\n    ROUND(co.burden_component,        2) AS burden_component,\n    ROUND(co.capacity_component,      2) AS capacity_component,\n    ROUND(co.vulnerability_component, 2) AS vulnerability_component,\n    ROUND(co.egi_score,               2) AS egi_score,\n    DENSE_RANK() OVER (ORDER BY co.egi_score DESC) AS egi_rank,\n    NTILE(5)     OVER (ORDER BY co.egi_score DESC) AS egi_quintile\nFROM combined co\nJOIN counties c USING (fips)\nORDER BY co.egi_score DESC,\n         co.vulnerability_component DESC,\n         c.population DESC,\n         c.fips ASC;\n\n-- Confirm view created (visible when running this file standalone).\nSELECT 'v_equity_gap_index created' AS status;\n\n-- Top 10 preview (visible when running this file standalone).\nSELECT * FROM v_equity_gap_index LIMIT 10;\n",
  "q06_top_underserved.sql": "-- =============================================================================\n-- q06_top_underserved.sql — top 10 EGI counties with driver profile\n-- =============================================================================\n-- PURPOSE:    Surface the 10 most-underserved Mississippi counties from\n--             v_equity_gap_index along with a derived driver_profile that\n--             tells the reader at a glance whether each county's high EGI\n--             comes from a single extreme pillar or all three pillars\n--             together. Makes D-019's promise of transparency visible\n--             (per DECISIONS.md D-019 note).\n-- TABLES:     v_equity_gap_index\n-- TECHNIQUES: UNPIVOT via UNION ALL (3 components -> long form),\n--             ROW_NUMBER() OVER (PARTITION BY fips ORDER BY val DESC),\n--             conditional MAX aggregation, CASE for driver_profile bins,\n--             multi-CTE composition.\n-- OUTPUT:     10 rows: fips, county_name, region, population,\n--             burden_component, capacity_component, vulnerability_component,\n--             egi_score, egi_rank, dominant_component (TEXT),\n--             driver_profile (TEXT — one of \"single-component dominant\",\n--             \"one component leading\", \"multi-component\").\n-- DESIGN:     driver_profile thresholds (30 pp / 15 pp) come from DECISIONS.md D-019;\n--             chosen to make the Issaquena case (\"multi-component\", top vs\n--             second gap = 9.88) visibly different from any single-component\n--             counter-example. UNPIVOT was chosen over nested CASE because\n--             extracting both max and second_max via CASE in SQL requires\n--             ~12 nested WHEN clauses and is fragile. The UNPIVOT pattern\n--             scales cleanly if components are ever added/removed.\n-- =============================================================================\n\nWITH\n-- 1. The top 10 EGI counties (rank <= 10).\ntop10 AS (\n    SELECT *\n    FROM v_equity_gap_index\n    WHERE egi_rank <= 10\n),\n\n-- 2. UNPIVOT: turn the 3 component columns into 3 rows per county.\n--    Gives us a long-form table we can window over.\ncomponents_long AS (\n    SELECT fips, 'Burden'        AS component, burden_component        AS val FROM top10\n    UNION ALL\n    SELECT fips, 'Capacity',           capacity_component                   FROM top10\n    UNION ALL\n    SELECT fips, 'Vulnerability',      vulnerability_component              FROM top10\n),\n\n-- 3. Rank the 3 components within each county; component_rank=1 is the\n--    dominant component, component_rank=2 is the runner-up.\nranked AS (\n    SELECT\n        fips,\n        component,\n        val,\n        ROW_NUMBER() OVER (PARTITION BY fips ORDER BY val DESC) AS component_rank\n    FROM components_long\n),\n\n-- 4. Collapse back to one row per county with the top + second-top extracted\n--    via conditional MAX. dominant_component is the label of the top one;\n--    max/second_max are the numeric values used for the driver_profile bin.\nextremes AS (\n    SELECT\n        fips,\n        MAX(CASE WHEN component_rank = 1 THEN component END) AS dominant_component,\n        MAX(CASE WHEN component_rank = 1 THEN val       END) AS max_component,\n        MAX(CASE WHEN component_rank = 2 THEN val       END) AS second_max_component\n    FROM ranked\n    GROUP BY fips\n)\n\n-- 5. Join top10 + extremes; derive driver_profile via the 30/15 pp bins\n--    from the DECISIONS.md D-019 spec.\nSELECT\n    t.fips,\n    t.county_name,\n    t.region,\n    t.population,\n    t.burden_component,\n    t.capacity_component,\n    t.vulnerability_component,\n    t.egi_score,\n    t.egi_rank,\n    e.dominant_component,\n    CASE\n        WHEN (e.max_component - e.second_max_component) > 30 THEN 'single-component dominant'\n        WHEN (e.max_component - e.second_max_component) > 15 THEN 'one component leading'\n        ELSE 'multi-component'\n    END AS driver_profile\nFROM top10 t\nJOIN extremes e USING (fips)\nORDER BY t.egi_rank;\n",
  "q07_regional_patterns.sql": "-- =============================================================================\n-- q07_regional_patterns.sql — Delta vs non-Delta + rural vs urban contrast\n-- =============================================================================\n-- PURPOSE:    Produce summary contrasts of the EGI and its three components\n--             across two policy-salient county groupings: (A) Delta vs\n--             non-Delta, and (B) rural (pop < 50,000) vs urban. Each\n--             section reports county count, component means, EGI mean,\n--             EGI max, and the name of the highest-EGI county in the group.\n-- TABLES:     v_equity_gap_index, counties\n-- TECHNIQUES: 2 result sets in one file; window function ROW_NUMBER() per\n--             group to identify the top-EGI county; conditional MAX\n--             aggregation to surface the top name; GROUP BY with derived\n--             group-name column via CASE.\n-- OUTPUT:     SECTION A — Delta vs non-Delta: 2 rows\n--             SECTION B — Rural vs urban: 2 rows\n--             Both sections share columns: group_name, county_count,\n--             mean_burden, mean_capacity, mean_vulnerability, mean_egi,\n--             max_egi, top_egi_county.\n-- DESIGN:     The same query pattern is used for both sections — only the\n--             grouping column changes (is_delta vs is_rural). is_delta and\n--             is_rural live on the counties table (not on v_equity_gap_index),\n--             so each section starts by joining counties. CSV exporter saves\n--             both sections to separate files (q07a, q07b) since Phase 4\n--             may want both at-a-glance contrasts.\n-- =============================================================================\n\n-- ----------------------------------------------------------------------------\n-- SECTION A — Delta vs non-Delta\n-- ----------------------------------------------------------------------------\nWITH v_flagged_a AS (\n    SELECT v.*, c.is_delta\n    FROM v_equity_gap_index v\n    JOIN counties c USING (fips)\n),\nranked_a AS (\n    SELECT\n        v.*,\n        ROW_NUMBER() OVER (PARTITION BY is_delta ORDER BY egi_score DESC) AS rn\n    FROM v_flagged_a v\n)\nSELECT\n    CASE WHEN is_delta = 1 THEN 'Delta' ELSE 'Non-Delta' END AS group_name,\n    COUNT(*)                                        AS county_count,\n    ROUND(AVG(burden_component),        2)          AS mean_burden,\n    ROUND(AVG(capacity_component),      2)          AS mean_capacity,\n    ROUND(AVG(vulnerability_component), 2)          AS mean_vulnerability,\n    ROUND(AVG(egi_score),               2)          AS mean_egi,\n    ROUND(MAX(egi_score),               2)          AS max_egi,\n    MAX(CASE WHEN rn = 1 THEN county_name END)      AS top_egi_county\nFROM ranked_a\nGROUP BY is_delta\nORDER BY mean_egi DESC;\n\n\n-- ----------------------------------------------------------------------------\n-- SECTION B — Rural vs urban (is_rural derived from population < 50,000)\n-- ----------------------------------------------------------------------------\nWITH v_flagged_b AS (\n    SELECT v.*, c.is_rural\n    FROM v_equity_gap_index v\n    JOIN counties c USING (fips)\n),\nranked_b AS (\n    SELECT\n        v.*,\n        ROW_NUMBER() OVER (PARTITION BY is_rural ORDER BY egi_score DESC) AS rn\n    FROM v_flagged_b v\n)\nSELECT\n    CASE WHEN is_rural = 1 THEN 'Rural (pop < 50k)' ELSE 'Urban (pop >= 50k)' END AS group_name,\n    COUNT(*)                                        AS county_count,\n    ROUND(AVG(burden_component),        2)          AS mean_burden,\n    ROUND(AVG(capacity_component),      2)          AS mean_capacity,\n    ROUND(AVG(vulnerability_component), 2)          AS mean_vulnerability,\n    ROUND(AVG(egi_score),               2)          AS mean_egi,\n    ROUND(MAX(egi_score),               2)          AS max_egi,\n    MAX(CASE WHEN rn = 1 THEN county_name END)      AS top_egi_county\nFROM ranked_b\nGROUP BY is_rural\nORDER BY mean_egi DESC;\n",
  "q08_drivers_analysis.sql": "-- =============================================================================\n-- q08_drivers_analysis.sql — per-county drivers for the top-10 EGI counties\n-- =============================================================================\n-- PURPOSE:    For each of the 10 most-underserved counties, identify the\n--             specific drivers behind its underservedness: which 2 PLACES\n--             burden measures most exceed state mean (polarity-aware),\n--             whether the county has zero attributed primary-care providers,\n--             and which SVI theme is dominant. One row per top-10 county.\n-- TABLES:     v_equity_gap_index, health_indicators, measures,\n--             social_vulnerability\n-- TECHNIQUES: 6 chained CTEs (top10 filter, latest year, state means,\n--             polarity-aware deviation per county-measure, ROW_NUMBER\n--             ranking, dominant_svi via CASE reused from q04),\n--             conditional MAX aggregation to pivot dev_rank=1 / dev_rank=2\n--             into named columns.\n-- OUTPUT:     10 rows: fips, county_name, egi_rank,\n--             top_burden_measure_1 (most extreme deviation from state mean),\n--             top_burden_measure_2 (second-most extreme),\n--             has_zero_providers (0/1), dominant_svi_theme (TEXT).\n-- DESIGN:     \"burden deviation\" is computed as polarity * (county_value -\n--             state_mean) so that both polarity=+1 measures (where higher =\n--             worse) and polarity=-1 measures (where lower = worse) point\n--             in the same direction: positive deviation = county is more\n--             burdened than state average on that measure. The top-2 by\n--             deviation are then the most extreme negative drivers for\n--             that county. has_zero_providers uses\n--             capacity_component = 100 (the only way to get exactly 100\n--             under the min-max scoring is to have the minimum pcp_per_10k,\n--             which in MS is 0 — verified post D-010 amendment).\n-- =============================================================================\n\nWITH\n-- 1. The 10 top-EGI counties.\ntop10 AS (\n    SELECT * FROM v_equity_gap_index WHERE egi_rank <= 10\n),\n\n-- 2. Latest BRFSS year per PLACES measure (year-mix per Convention C3).\nlatest AS (\n    SELECT measure_id, MAX(year) AS y\n    FROM health_indicators\n    GROUP BY measure_id\n),\n\n-- 3. State means for the 10 burden composite measures, age-adjusted.\nstate_means AS (\n    SELECT m.measure_id, AVG(hi.data_value) AS state_mean\n    FROM health_indicators hi\n    JOIN measures m USING (measure_id)\n    JOIN latest l  ON l.measure_id = hi.measure_id AND l.y = hi.year\n    WHERE hi.data_value_type      = 'Age-adjusted prevalence'\n      AND m.is_in_burden_composite = 1\n    GROUP BY m.measure_id\n),\n\n-- 4. For each top-10 county x burden measure: deviation from state mean,\n--    polarity-applied so positive deviation = more burdened than state avg.\n--    ROW_NUMBER ranks deviations within each county; dev_rank=1 is the\n--    biggest \"above state mean\" driver.\ncounty_burden_dev AS (\n    SELECT\n        hi.fips,\n        m.measure_short,\n        m.polarity * (hi.data_value - sm.state_mean) AS burden_deviation,\n        ROW_NUMBER() OVER (\n            PARTITION BY hi.fips\n            ORDER BY m.polarity * (hi.data_value - sm.state_mean) DESC\n        ) AS dev_rank\n    FROM health_indicators hi\n    JOIN measures m USING (measure_id)\n    JOIN latest l     ON l.measure_id = hi.measure_id AND l.y = hi.year\n    JOIN state_means sm USING (measure_id)\n    JOIN top10 t      ON t.fips = hi.fips\n    WHERE hi.data_value_type      = 'Age-adjusted prevalence'\n      AND m.is_in_burden_composite = 1\n),\n\n-- 5. Pivot dev_rank=1 / dev_rank=2 into named columns per county.\ntop_burdens AS (\n    SELECT\n        fips,\n        MAX(CASE WHEN dev_rank = 1 THEN measure_short END) AS top_burden_measure_1,\n        MAX(CASE WHEN dev_rank = 2 THEN measure_short END) AS top_burden_measure_2\n    FROM county_burden_dev\n    GROUP BY fips\n),\n\n-- 6. Dominant SVI theme per county (CASE chain reused from q04;\n--    declared order resolves ties theme1 > theme2 > theme3 > theme4).\ndominant_svi AS (\n    SELECT\n        fips,\n        CASE\n            WHEN rpl_theme1_socioeconomic >= rpl_theme2_household\n             AND rpl_theme1_socioeconomic >= rpl_theme3_minority\n             AND rpl_theme1_socioeconomic >= rpl_theme4_housing_transport\n                THEN 'Socioeconomic Status'\n            WHEN rpl_theme2_household >= rpl_theme3_minority\n             AND rpl_theme2_household >= rpl_theme4_housing_transport\n                THEN 'Household Characteristics'\n            WHEN rpl_theme3_minority >= rpl_theme4_housing_transport\n                THEN 'Racial & Ethnic Minority Status'\n            ELSE 'Housing Type & Transportation'\n        END AS dominant_svi_theme\n    FROM social_vulnerability\n)\n\n-- 7. One row per top-10 county with all 3 driver signals.\nSELECT\n    t.fips,\n    t.county_name,\n    t.egi_rank,\n    tb.top_burden_measure_1,\n    tb.top_burden_measure_2,\n    CASE WHEN t.capacity_component = 100.0 THEN 1 ELSE 0 END AS has_zero_providers,\n    ds.dominant_svi_theme\nFROM top10 t\nJOIN top_burdens  tb USING (fips)\nJOIN dominant_svi ds USING (fips)\nORDER BY t.egi_rank;\n",
};

export const SQL_FILE_LIST = Object.keys(SQL_FILES);
